starter.Ticker.tsx:
import { useEffect, useState } from 'react';

export function Ticker({ delay }: { delay: number }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    setInterval(() => setN((v) => v + 1), delay);
  }, [delay]);
  return <span>{n}</span>;
}

